{
  "name": "ngx-smart-components",
  "$schema": "../../node_modules/nx/schemas/project-schema.json",
  "sourceRoot": "packages/ngx-smart-components/src",
  "prefix": "smart",
  "projectType": "library",
  "release": {
    "version": {
      "manifestRootsToUpdate": ["dist/{projectRoot}"],
      "currentVersionResolver": "git-tag",
      "fallbackCurrentVersionResolver": "disk"
    }
  },
  "tags": [],
  "targets": {
    "build": {
      "executor": "@nx/angular:package",
      "outputs": ["{workspaceRoot}/dist/{projectRoot}"],
      "options": {
        "project": "packages/ngx-smart-components/ng-package.json",
        "tsConfig": "packages/ngx-smart-components/tsconfig.lib.json"
      },
      "configurations": {
        "production": {
          "tsConfig": "packages/ngx-smart-components/tsconfig.lib.prod.json"
        },
        "development": {}
      },
      "defaultConfiguration": "production"
    },
    "nx-release-publish": {
      "options": {
        "packageRoot": "dist/{projectRoot}"
      }
    },
    "test": {
      "executor": "@nx/angular:unit-test",
      "options": {}
    },
    "lint": {
      "executor": "@nx/eslint:lint"
    },
    "storybook": {
      "continuous": true,
      "executor": "@storybook/angular:start-storybook",
      "outputs": ["{projectRoot}/documentation.json"],
      "options": {
        "port": 4200,
        "configDir": "packages/ngx-smart-components/.storybook",
        "compodoc": true,
        "compodocArgs": [
          "-e",
          "json",
          "-p",
          "packages/ngx-smart-components/tsconfig.lib.json",
          "-d",
          "packages/ngx-smart-components"
        ]
      },
      "configurations": {
        "ci": {
          "quiet": true
        }
      }
    },
    "build-storybook": {
      "executor": "@storybook/angular:build-storybook",
      "outputs": ["{options.outputDir}", "{projectRoot}/documentation.json"],
      "options": {
        "outputDir": "dist/storybook/ngx-smart-components",
        "configDir": "packages/ngx-smart-components/.storybook",
        "compodoc": true,
        "compodocArgs": [
          "-e",
          "json",
          "-p",
          "packages/ngx-smart-components/tsconfig.lib.json",
          "-d",
          "packages/ngx-smart-components"
        ]
      },
      "configurations": {
        "ci": {
          "quiet": true
        }
      }
    },
    "test-storybook": {
      "executor": "nx:run-commands",
      "options": {
        "_comment": "url port must match storybook target options.port (currently 4200)",
        "command": "test-storybook -c packages/ngx-smart-components/.storybook --url=http://localhost:4200"
      }
    },
    "validate-docs-json": {
      "executor": "nx:run-commands",
      "cache": false,
      "dependsOn": ["build-storybook"],
      "options": {
        "command": "node packages/ngx-smart-components/scripts/validate-docs-json.mjs"
      }
    },
    "static-storybook": {
      "executor": "@nx/web:file-server",
      "dependsOn": ["validate-docs-json"],
      "continuous": true,
      "options": {
        "staticFilePath": "dist/storybook/ngx-smart-components",
        "spa": true
      },
      "configurations": {
        "ci": {}
      }
    }
  }
}

